void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // PAINTERLY EFFECT:
    vec2 t = 0.005 + 0.045*clamp01(vec2(audioLow,audioHigh)-1);

   vUv += texture(sampler_noise_hq, rand_frame.xy + vUv*3.3*uTexSize.xy*texsize_noise_hq.zw)*uTexSize.zw*6;

vec2 uv2 = vUv;
    vec2 delta2 = uTexSize.zw*vec2(1,1);
    vec3 blurry_color = texture( sampler_main,
        mix(vUv,vUvOriginal,-1) + delta2 ).xyz;
    vec2 v = (blurry_color.xy-0.27) * t;
      //uv2 += v;
